export type Question = {
  id: string;
  prompt: string;
  /** Expected answer. Compared exactly for typing, else case/space-insensitive. */
  answer: string;
  /** Reference sentence for the typing variant (equals `answer`). */
  reference?: string;
  /** Multiple-choice options (logic, trivia L1-3). When present, `answer` is the correct option. */
  options?: string[];
  /** Extra acceptable answers for fuzzy-matched typed questions (trivia L4-5). */
  accept?: string[];
};

/** The friction ladder caps here; difficulty never climbs past this level. */
export const MAX_LEVEL = 5;
/** Clamp a ladder level to the curated 1..MAX_LEVEL range. */
const clampLevel = (lvl: number) => Math.max(1, Math.min(MAX_LEVEL, lvl));

